                "direction": "REDUCE",
                "eventWindow": {
                  "startDate": "2026-04-01T08:30:00Z",
                  "endDate": "2026-04-01T10:30:00Z"
                },
                "capacityType": "CURTAILMENT",
                "maxCapacityKw": 20000
              }
            }
          ],
          "offer": {
