            "offerAttributes": {
              "@context": "https://schema.beckn.io/DemandFlexBuyOffer/v2.0/context.jsonld",
              "@type": "DemandFlexBuyOffer",
              "inputs": [
                {
                  "role": "buyer",
                  "participantId": "tpddl-north-delhi",
                  "inputs": {
                    "incentivePerKwh": 3.5,
                    "currency": "INR",
                    "baselineMethodology": {
                      "bestOf": 5,
                      "outOf": 10
                    },
                    "penaltyRate": 1.5,
                    "premiumForGuaranteed": 5.0,
                    "optOutDefault": false
                  }
                },
                {
                  "role": "seller",
                  "participantId": "greenflex-agg",
                  "inputs": {
                    "plannedDemandChange": {
                      "@type": "Quantity",
                      "unitCode": "KWH",
                      "unitQuantity": 6000.0
                    },
