        "roles": [
          {"role": "buyer", "participantId": "tpddl-north-delhi"},
          {"role": "seller", "participantId": "greenflex-agg"}
        ],
        "policy": {
          "url": "https://raw.githubusercontent.com/beckn/DEG/refs/heads/main/specification/policies/demand_flex_revenue.rego",
